BEGIN TRANSACTION;
CREATE TABLE benefit_records (
	id INTEGER NOT NULL, 
	customer_id INTEGER NOT NULL, 
	employee_id INTEGER NOT NULL, 
	mes_referencia VARCHAR(7) NOT NULL, 
	tipo_beneficio VARCHAR(100) NOT NULL, 
	descricao TEXT, 
	valor FLOAT, 
	quantidade FLOAT, 
	valor_total FLOAT, 
	status VARCHAR(20), 
	observacoes TEXT, 
	created_at DATETIME, 
	updated_at DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(customer_id) REFERENCES customers (id), 
	FOREIGN KEY(employee_id) REFERENCES employees (id)
);
CREATE TABLE billing_additional_values (
	id INTEGER NOT NULL, 
	codccu VARCHAR(50) NOT NULL, 
	nome_ccu VARCHAR(255), 
	descricao VARCHAR(255), 
	valor FLOAT, 
	created_at DATETIME, 
	updated_at DATETIME, 
	PRIMARY KEY (id)
);
CREATE TABLE billing_companies (
	id INTEGER NOT NULL, 
	name VARCHAR(255) NOT NULL, 
	cnpj_femsa VARCHAR(20) NOT NULL, 
	created_at DATETIME, 
	PRIMARY KEY (id)
);
CREATE TABLE billing_employees (
	id INTEGER NOT NULL, 
	cpf VARCHAR(14) NOT NULL, 
	nome VARCHAR(255) NOT NULL, 
	created_at DATETIME, 
	PRIMARY KEY (id)
);
CREATE TABLE billing_employment_contracts (
	id INTEGER NOT NULL, 
	employee_id INTEGER NOT NULL, 
	company_id INTEGER NOT NULL, 
	unit_id INTEGER NOT NULL, 
	cargo VARCHAR(255), 
	funcao VARCHAR(255), 
	salario_base FLOAT, 
	data_admissao DATE, 
	data_demissao DATE, 
	data_termino_contrato DATE, 
	created_at DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(employee_id) REFERENCES billing_employees (id), 
	FOREIGN KEY(company_id) REFERENCES billing_companies (id), 
	FOREIGN KEY(unit_id) REFERENCES billing_units (id)
);
CREATE TABLE billing_exam_records (
	id INTEGER NOT NULL, 
	billing_period_id INTEGER NOT NULL, 
	unit_id INTEGER, 
	employee_id INTEGER, 
	tipo VARCHAR(100), 
	exame VARCHAR(255), 
	data_pedido DATE, 
	data_exame DATE, 
	data_inativacao DATE, 
	valor_cobrar FLOAT, 
	created_at DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(billing_period_id) REFERENCES billing_periods (id), 
	FOREIGN KEY(unit_id) REFERENCES billing_units (id), 
	FOREIGN KEY(employee_id) REFERENCES billing_employees (id)
);
CREATE TABLE billing_payroll_item_types (
	id INTEGER NOT NULL, 
	code VARCHAR(50) NOT NULL, 
	description VARCHAR(255) NOT NULL, 
	"group" VARCHAR(100), 
	direction VARCHAR(6), 
	PRIMARY KEY (id)
);
CREATE TABLE billing_payroll_items (
	id INTEGER NOT NULL, 
	billing_period_id INTEGER NOT NULL, 
	employee_id INTEGER NOT NULL, 
	contract_id INTEGER, 
	unit_id INTEGER, 
	payroll_item_type_id INTEGER NOT NULL, 
	quantity FLOAT, 
	amount FLOAT, 
	source_column VARCHAR(100), 
	notes VARCHAR(500), 
	created_at DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(billing_period_id) REFERENCES billing_periods (id), 
	FOREIGN KEY(employee_id) REFERENCES billing_employees (id), 
	FOREIGN KEY(contract_id) REFERENCES billing_employment_contracts (id), 
	FOREIGN KEY(unit_id) REFERENCES billing_units (id), 
	FOREIGN KEY(payroll_item_type_id) REFERENCES billing_payroll_item_types (id)
);
CREATE TABLE billing_periods (
	id INTEGER NOT NULL, 
	company_id INTEGER NOT NULL, 
	mes_referencia VARCHAR(7) NOT NULL, 
	status VARCHAR(10), 
	created_at DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(company_id) REFERENCES billing_companies (id)
);
CREATE TABLE billing_units (
	id INTEGER NOT NULL, 
	company_id INTEGER NOT NULL, 
	cnpj_unidade VARCHAR(20) NOT NULL, 
	nome_unidade VARCHAR(255) NOT NULL, 
	centro_custo_femsa VARCHAR(100), 
	created_at DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(company_id) REFERENCES billing_companies (id)
);
CREATE TABLE customers (
	id INTEGER NOT NULL, 
	name VARCHAR NOT NULL, 
	email VARCHAR, 
	phone VARCHAR, 
	company VARCHAR, 
	address VARCHAR, 
	city VARCHAR, 
	state VARCHAR, 
	country VARCHAR, 
	postal_code VARCHAR, 
	customer_type VARCHAR, 
	status VARCHAR, 
	total_revenue FLOAT, 
	created_at DATETIME, 
	updated_at DATETIME, description TEXT, 
	PRIMARY KEY (id)
);
CREATE TABLE employees (
	id INTEGER NOT NULL, 
	first_name VARCHAR NOT NULL, 
	last_name VARCHAR NOT NULL, 
	email VARCHAR NOT NULL, 
	phone VARCHAR, 
	department VARCHAR, 
	position VARCHAR, 
	salary FLOAT, 
	hire_date DATETIME, 
	status VARCHAR, 
	created_at DATETIME, 
	updated_at DATETIME, 
	PRIMARY KEY (id)
);
CREATE TABLE exam_records (
	id INTEGER NOT NULL, 
	customer_id INTEGER NOT NULL, 
	employee_id INTEGER NOT NULL, 
	tipo_exame VARCHAR(100) NOT NULL, 
	data_exame VARCHAR(10) NOT NULL, 
	data_validade VARCHAR(10), 
	status VARCHAR(50), 
	resultado VARCHAR(100), 
	clinica VARCHAR(200), 
	medico VARCHAR(200), 
	crm VARCHAR(20), 
	observacoes TEXT, 
	arquivo_path VARCHAR(500), 
	created_at DATETIME, 
	updated_at DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(customer_id) REFERENCES customers (id), 
	FOREIGN KEY(employee_id) REFERENCES employees (id)
);
CREATE TABLE integrations (
	id INTEGER NOT NULL, 
	name VARCHAR NOT NULL, 
	integration_type VARCHAR NOT NULL, 
	api_endpoint VARCHAR, 
	api_key_name VARCHAR, 
	description TEXT, 
	is_active BOOLEAN, 
	last_sync DATETIME, 
	sync_frequency VARCHAR, 
	config_json TEXT, 
	created_at DATETIME, 
	updated_at DATETIME, 
	PRIMARY KEY (id)
);
CREATE TABLE report_templates (
	id INTEGER NOT NULL, 
	customer_id INTEGER NOT NULL, 
	name VARCHAR NOT NULL, 
	file_path VARCHAR NOT NULL, 
	created_at DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(customer_id) REFERENCES customers (id)
);
CREATE TABLE reports (
	id INTEGER NOT NULL, 
	name VARCHAR NOT NULL, 
	report_type VARCHAR NOT NULL, 
	file_path VARCHAR, 
	file_format VARCHAR, 
	description TEXT, 
	status VARCHAR, 
	generated_by VARCHAR, 
	parameters TEXT, 
	created_at DATETIME, 
	completed_at DATETIME, 
	PRIMARY KEY (id)
);
CREATE TABLE sessions (
	id VARCHAR NOT NULL, 
	data TEXT NOT NULL, 
	created_at DATETIME, 
	expires_at DATETIME NOT NULL, 
	PRIMARY KEY (id)
);
CREATE TABLE time_records (
	id INTEGER NOT NULL, 
	customer_id INTEGER NOT NULL, 
	employee_id INTEGER NOT NULL, 
	mes_referencia VARCHAR(7) NOT NULL, 
	data VARCHAR(10) NOT NULL, 
	horas_trabalhadas FLOAT, 
	horas_extras FLOAT, 
	horas_noturnas FLOAT, 
	faltas FLOAT, 
	atrasos FLOAT, 
	adicional_noturno FLOAT, 
	dsr FLOAT, 
	banco_horas FLOAT, 
	observacoes TEXT, 
	created_at DATETIME, 
	updated_at DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(customer_id) REFERENCES customers (id), 
	FOREIGN KEY(employee_id) REFERENCES employees (id)
);
CREATE TABLE users (
	id INTEGER NOT NULL, 
	username VARCHAR NOT NULL, 
	password_hash VARCHAR NOT NULL, 
	email VARCHAR, 
	full_name VARCHAR, 
	is_active BOOLEAN, 
	created_at DATETIME, 
	last_login DATETIME, 
	PRIMARY KEY (id)
);
CREATE INDEX ix_customers_id ON customers (id);
CREATE INDEX ix_customers_name ON customers (name);
CREATE UNIQUE INDEX ix_customers_email ON customers (email);
CREATE UNIQUE INDEX ix_employees_email ON employees (email);
CREATE INDEX ix_employees_id ON employees (id);
CREATE INDEX ix_integrations_id ON integrations (id);
CREATE UNIQUE INDEX ix_integrations_name ON integrations (name);
CREATE INDEX ix_reports_id ON reports (id);
CREATE INDEX ix_reports_name ON reports (name);
CREATE INDEX ix_users_id ON users (id);
CREATE UNIQUE INDEX ix_users_username ON users (username);
CREATE UNIQUE INDEX ix_users_email ON users (email);
CREATE INDEX ix_sessions_id ON sessions (id);
CREATE INDEX ix_report_templates_id ON report_templates (id);
CREATE INDEX ix_benefit_records_id ON benefit_records (id);
CREATE INDEX ix_benefit_records_mes_referencia ON benefit_records (mes_referencia);
CREATE INDEX ix_time_records_id ON time_records (id);
CREATE INDEX ix_time_records_mes_referencia ON time_records (mes_referencia);
CREATE INDEX ix_exam_records_id ON exam_records (id);
CREATE INDEX ix_exam_records_data_exame ON exam_records (data_exame);
CREATE UNIQUE INDEX ix_billing_companies_cnpj_femsa ON billing_companies (cnpj_femsa);
CREATE INDEX ix_billing_companies_id ON billing_companies (id);
CREATE UNIQUE INDEX ix_billing_employees_cpf ON billing_employees (cpf);
CREATE INDEX ix_billing_employees_id ON billing_employees (id);
CREATE INDEX ix_billing_payroll_item_types_id ON billing_payroll_item_types (id);
CREATE UNIQUE INDEX ix_billing_payroll_item_types_code ON billing_payroll_item_types (code);
CREATE INDEX ix_billing_units_id ON billing_units (id);
CREATE UNIQUE INDEX ix_billing_units_cnpj_unidade ON billing_units (cnpj_unidade);
CREATE INDEX ix_billing_periods_id ON billing_periods (id);
CREATE INDEX ix_billing_employment_contracts_id ON billing_employment_contracts (id);
CREATE INDEX ix_billing_exam_records_id ON billing_exam_records (id);
CREATE INDEX ix_billing_payroll_items_id ON billing_payroll_items (id);
CREATE INDEX ix_billing_additional_values_id ON billing_additional_values (id);
CREATE INDEX ix_billing_additional_values_codccu ON billing_additional_values (codccu);
COMMIT;
